function varargout = IM1_mix(varargin)
%IM1_MIX  Self-contained mixed-variable MOO adaptation of IM1.
%
% Auto-generated by generate_selfcontained_wrappers_MOO_mix.m
% Source: IM1, n=2, m=2, strategy=progressive, kappa=1000000
% Variable pattern: C,K
% D variables: nonuniform sorted finite sets with injected anchors.
% K variables: labels with permuted nonuniform numeric embeddings; labels carry no ordinal information.
%
%   x1   C [1,4] -> orig [1,4]
%   x2   K labels {k2_1,...,k2_42}, 42 levels, permuted embedding in [1,2]
%
% Usage:
%   PB = IM1_mix()
%   F  = PB.func_F(xcell)       % recommended inside benchmark loops
%   F  = IM1_mix(xcell)              % also valid; PB is memoized persistently
%   PD = IM1_mix('ProblemData')
%

persistent PB_cached
if isempty(PB_cached)
lb_orig = [1; 1];
ub_orig = [4; 2];
lb_C_work = [1; 1];
ub_C_work = [4; 2];
var_types = {'C', 'K'};
K2_labels = { ...
    'k2_1', 'k2_2', 'k2_3', 'k2_4', 'k2_5', 'k2_6', 'k2_7', 'k2_8', 'k2_9', 'k2_10', ...
    'k2_11', 'k2_12', 'k2_13', 'k2_14', 'k2_15', 'k2_16', 'k2_17', 'k2_18', 'k2_19', 'k2_20', ...
    'k2_21', 'k2_22', 'k2_23', 'k2_24', 'k2_25', 'k2_26', 'k2_27', 'k2_28', 'k2_29', 'k2_30', ...
    'k2_31', 'k2_32', 'k2_33', 'k2_34', 'k2_35', 'k2_36', 'k2_37', 'k2_38', 'k2_39', 'k2_40', ...
    'k2_41', 'k2_42'};
K2_embed  = [ ...
    1.472508641134054; 1.400403642003401; 1.042526651504305; 1.5; 1.551669141707114; 1.94245955766781; 1.157880097585123; 1.731888200827286; ...
    1.009928456670077; 1.033831304485758; 1.138666883853426; 1.089523646898275; 1.305052623739506; 2; 1.886898255665015; 1.366937229742479; ...
    1.075862304184457; 1.781632990867162; 1.684040869430125; 1.014373218903254; 1.000710870895129; 1.435586026089255; 1.224457012314448; 1.593953163193566; ...
    1.00013468484905; 1.276583153497496; 1.026272461635376; 1.638069733781952; 1.104521757164756; 1.511195249232327; 1.120891608260273; 1.006409833584465; ...
    1; 1.063501325316034; 1.833296150868664; 1.00188109078184; 1.249727028949835; 1.003751999078642; 1.200745145241382; 1.335162004396278; ...
    1.019803169861925; 1.05240270847173; ...
];
ProblemData = { ...
    [1; 4]; ... % x1 C
    K2_labels; ... % x2 K
};
x_anchor = {2.5, 'k2_4'};
anchors_set = [2.5 1 4; 1.5 1 2];

PB = struct();
PB.name = 'IM1_mix';
PB.problem = 'IM1';
PB.source = 'MOModels_Matlab';
PB.type = 'MOO_MIXED';
PB.nvar = 2; PB.n = 2; PB.nobj = 2; PB.m = 2;
